settings.custom_liquid:
{% if product.selected_or_first_available_variant.available and product.selected_or_first_available_variant.inventory_management == 'shopify' %}
  {% assign inventory = product.selected_or_first_available_variant.inventory_quantity %}
  {% if inventory > 0 %}
    <p style="font-weight: 500; color: #d00; font-size: 16px;">
      Limited quantity! 🔥 only {{ inventory }} pieces left in stock
    </p>
  {% endif %}
{% endif %}

{% if request.path == '/products/7-led-lifting-and-firming-facial-device' %}
  <style>
    .step-scroll {
      display: flex;
      gap: 60px;
      overflow-x: auto;
      scroll-snap-type: x mandatory;
      -webkit-overflow-scrolling: touch;
      padding-bottom: 10px;
      scroll-padding-left: 20px;
    }

    .step-item {
      flex: 0 0 auto;
      width: 100%;
      max-width: 380px;
      scroll-snap-align: start;
      text-align: center;
    }

    .step-image {
      width: 100%;
      height: 380px;
      border-radius: 20px;
      overflow: hidden;
      background-color: #f0f0f0;
      margin: 0 auto 20px;
    }

    .step-image img {
      width: 100%;
      height: 100%;
      object-fit: cover;
    }

    .step-title {
      font-size: 18px;
      font-weight: 700;
      margin-bottom: 10px;
    }

    .step-text {
      font-size: 14px;
      line-height: 1.6;
      color: #333;
    }

    /* Центрування на desktop */
    @media screen and (min-width: 769px) {
      .step-scroll {
        justify-content: center;
        overflow-x: visible;
      }
    }
  </style>

  <div style="padding: 60px 20px; background-color: #fff; text-align: center;">
    <h2 style="font-size: 26px; font-weight: 600; margin-bottom: 40px;">
      <span style="color: #EC5F94; font-style: italic;">See results</span> in 3 simple steps
    </h2>

    <div class="step-scroll">
      <!-- Step 1 -->
      <div class="step-item">
        <div class="step-image">
          <img src="https://cdn.shopify.com/s/files/1/0951/2766/7027/files/step-1.webp" alt="Step 1 Image">
        </div>
        <h3 class="step-title">Step 1: Prep Your Skin</h3>
        <p class="step-text">
          Start with a clean face. Gently cleanse your skin and apply your favorite anti-aging serum we recommend pairing with our Hydrating Renewal Serum for optimal results, but you're welcome to use your own.
        </p>
      </div>

      <!-- Step 2 -->
      <div class="step-item">
        <div class="step-image">
          <img src="https://cdn.shopify.com/s/files/1/0951/2766/7027/files/step-2.webp" alt="Step 2 Image">
        </div>
        <h3 class="step-title">Step 2: Activate & Customize</h3>
        <p class="step-text">
          Hold the power button for 10 seconds until you hear a gentle hum this means your device is activated and ready. Select your preferred LED light therapy mode based on your skin goals: Red for anti-aging, green for fine lines & texture or all colors. Your personalized treatment awaits.
        </p>
      </div>

      <!-- Step 3 -->
      <div class="step-item">
        <div class="step-image">
          <img src="https://cdn.shopify.com/s/files/1/0951/2766/7027/files/step-3.webp" alt="Step 3 Image">
        </div>
        <h3 class="step-title">Step 3: Glide & Glow</h3>
        <p class="step-text">
          Slowly glide the LunaraLight across your face, jawline, and neck using gentle upward strokes. Let the EMS microcurrent and LED light therapy do the work lifting, toning and transforming your skin with every pass. Congrats you’re officially on your way to firmer, sculpted, radiant skin!
        </p>
      </div>
    </div>
  </div>
{% endif %}

