{% if request.path == '/products/lunara-light-mask-portable' %}
  <style>
    .comparison-wrapper {
      max-width: 1000px;
      margin: 0 auto;
    }

    .comparison-header,
    .comparison-row {
      display: flex;
      width: 100%;
      border-top: 1px solid #f0d4dc;
    }

    .comparison-col {
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 16px;
      font-size: 14px;
    }

    .comparison-col.feature {
      justify-content: flex-start;
      font-weight: 500;
      text-align: left;
      width: 50%;
    }

    .comparison-col.lunaskin {
      width: 25%;
      background-color: #FFDDE6;
    }

    .comparison-col.other {
      width: 25%;
    }

    .comparison-col.header {
      border-top: none;
    }

    .comparison-col.empty {
      visibility: hidden;
      height: 100px;
    }

    .comparison-col img.mask-image {
      min-height: 100px;
      height: auto;
      max-height: 140px;
    }

    .comparison-col.lunaskin img.icon,
    .comparison-col.other img.icon {
      height: 20px;
    }

    @media screen and (max-width: 768px) {
      .comparison-col.feature {
        font-size: 13px;
      }

      .comparison-col img.mask-image {
        min-height: auto;
        max-height: 100px;
      }

      .comparison-col.lunaskin img.icon,
      .comparison-col.other img.icon {
        height: 18px;
      }
    }
  </style>

  <div style="padding: 40px 20px; background-color: #fff;">
    <h2 style="text-align: center; font-size: 24px; font-weight: 600; margin-bottom: 40px;">
      Not Just Another LED Mask
    </h2>

    <div class="comparison-wrapper">
      <!-- Header row -->
      <div class="comparison-header">
        <div class="comparison-col feature">
          <div class="comparison-col empty"></div>
        </div>
        <div class="comparison-col lunaskin header">
          <img class="mask-image" src="https://cdn.shopify.com/s/files/1/0951/2766/7027/files/sky_mask.png" alt="Lunaskin Mask">
        </div>
        <div class="comparison-col other header">
          <img class="mask-image" src="https://cdn.shopify.com/s/files/1/0951/2766/7027/files/Another_mask.png?v=1749057464" alt="Other Mask">
        </div>
      </div>

      <!-- Comparison rows -->
      {% assign features = "Anatomical design,7 LED Colours,240 Medical-Grade LEDs,Waterproof Design,Eye Protection,Food-Grade Silicone,Affordable Cost" | split: "," %}
      {% assign lunaskin_icons = "Check.svg,Check.svg,Check.svg,Check.svg,Check.svg,Check.svg,Check.svg" | split: "," %}
      {% assign others_icons = "Cross.svg,Cross.svg,Cross.svg,Cross.svg,Cross.svg,Cross.svg,Check.svg" | split: "," %}

      {% for feature in features %}
        <div class="comparison-row">
          <div class="comparison-col feature">
            {{ feature }}
          </div>
          <div class="comparison-col lunaskin">
            <img class="icon" src="https://cdn.shopify.com/s/files/1/0951/2766/7027/files/{{ lunaskin_icons[forloop.index0] | strip }}" alt="icon">
          </div>
          <div class="comparison-col other">
            <img class="icon" src="https://cdn.shopify.com/s/files/1/0951/2766/7027/files/{{ others_icons[forloop.index0] | strip }}" alt="icon">
          </div>
        </div>
      {% endfor %}
    </div>
  </div>
{% endif %}

